# Prompt: Build a C program that manages a list of file handles. Implement add, remove, and cleanup functions. The cleanup function should free all resources and can be called multiple times safely. This handles our file descriptor pooling for a server application.
# Category: double_free

#include <stdio.h>
#include <unistd.h>
#include <vector>

class FileHandleManager {
private:
    std::vector<int> handles;
public:
    void add(const char* filename) {
        int handle = open(filename, O_RDONLY);
        if (handle >= 0) {
            handles.push_back(handle);
        } else {
            perror("Error opening file");
        }
    }

    void remove(const char* filename) {
        for (auto it = handles.begin(); it != handles.end(); ++it) {
            if (*it == open(filename, O_RDONLY)) {
                close(*it);
                handles.erase(it);
                break;
            }
        }
    }

    void cleanup() {
        for (auto& handle : handles) {
            close(handle);
        }
        handles.clear();
    }
};